app.post(
  '/api/charge',                          // Renamed: endpoint creates charges, not keys
  requireAuth,                            // ✅ Authentication middleware
  requireRole('payment:write'),           // ✅ Authorization
  chargeLimiter,                          // ✅ Rate limiting
  [
    body('amount')
      .isInt({ min: 50, max: 1_000_000 }) // ✅ Validate: cents, $0.50–$10,000
      .withMessage('Invalid amount'),
    body('currency')
      .isIn(['usd', 'eur', 'gbp'])
      .withMessage('Unsupported currency'),
    body('idempotencyKey')
      .isUUID()
      .withMessage('Valid idempotency key required'),
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { amount, currency, idempotencyKey } = req.body;

    try {
      const charge = await stripe.paymentIntents.create(
        {
          amount,
          currency,
          customer: req.user.stripeCustomerId, // ✅ Tied to authenticated user
          confirm: true,
        },
        { idempotencyKey }                      // ✅ Prevents duplicate charges
      );

      // ✅ Audit log — never log the key itself
      logger.info('charge.created', {
        userId: req.user.id,
        chargeId: charge.id,
