### `src/lib/auth/context.tsx` — The Core

```tsx
"use client";

import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useReducer,
  useRef,
} from "react";

import { AuthAPI } from "@/lib/api/auth";
import { AuthStorage } from "./storage";
import { isTokenExpiringSoon } from "./token";
import type {
  AuthContextValue,
  AuthState,
  AuthStatus,
  AuthTokens,
  User,
} from "./types";

// ─── Reducer ─────────────────────────────────────────────────────────────────

type AuthAction =
  | { type: "HYDRATE"; user: User; tokens: AuthTokens }
  | { type: "HYDRATE_EMPTY" }
  | { type: "LOGIN_START" }
  | { type: "LOGIN_SUCCESS"; user: User; tokens: AuthTokens }
  | { type: "LOGIN_FAILURE" }
  | { type: "LOGOUT" }
  | { type: "TOKEN_REFRESHED"; tokens: AuthTokens }
  | { type: "REFRESH_FAILED" };

const INITIAL_STATE: AuthState = {
  status: "idle",
  user: null,
  tokens: null,
  // Critically: false until client reconciles localStorage.
  // The server always renders with isHydrated: false.
  isHydrated: false,
};

function authReducer(state: AuthState, action: AuthAction): AuthState {
  switch (action.type) {
    case "HYDRATE":
      return {
        status: "authenticated",
        user: action.user,
        tokens: action.tokens,
        isHydrated: true,
      };

    case "HYDRATE_EMPTY":
      return { ...INITIAL_STATE, status: "unauthenticated", isHydrated: true };

    case "LOGIN_START":
      return { ...state, status: "loading" };

    case "LOGIN_SUCCESS":
      return {
        status: "authenticated",
        user: action.user,
        tokens: action.tokens,
        isHydrated: true,
      };

    case "LOGIN_FAILURE":
      return { ...state, status: "unauthenticated" };

    case "LOGOUT":
      return { ...INITIAL_STATE, status: "unauthenticated", isHydrated: true };

    case "TOKEN_REFRESHED":
      return { ...state, tokens: action.tokens };

    case "REFRESH_FAILED":
      return { ...INITIAL_STATE, status: "unauthenticated", isHydrated: true };

    default:
      return state;
  }
}

// ─── Context ─────────────────────────────────────────────────────────────────

const AuthContext = createContext<AuthContextValue | null>(null);

// ─── Provider ────────────────────────────────────────────────────────────────

interface AuthProviderProps {
  children: React.ReactNode;
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [state, dispatch] = useReducer(authReducer, INITIAL_STATE);

  // Prevent concurrent refresh attempts
  const isRefreshing = useRef(false);
  // Store refresh token outside state to avoid stale closures
  const refreshTokenRef = useRef<string | null>(null);

  // Keep ref in sync with state
  useEffect(() => {
    refreshTokenRef.current = state.tokens?.refreshToken ?? null;
  }, [state.tokens?.refreshToken]);

  // ── Refresh Session ────────────────────────────────────────────────────────

  const refreshSession = useCallback(async (): Promise<boolean> => {
    const refreshToken = refreshTokenRef.current;

